chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"save_page",title:"Save Page Link",contexts:["page"]}),chrome.contextMenus.create({id:"save_text",title:"Save Selected Text",contexts:["selection"]}),chrome.contextMenus.create({id:"save_image",title:"Save Image URL",contexts:["image"]})});chrome.contextMenus.onClicked.addListener(async(a,s)=>{try{let e={},t="";a.menuItemId==="save_page"?(t="url",e={url:s.url,title:s.title,type:t}):a.menuItemId==="save_text"?(t="url",e={text:a.selectionText,sourceUrl:s.url,type:t}):a.menuItemId==="save_image"&&(t="url",e={url:a.srcUrl,title:"Image from "+s.title,type:t});const c=new FormData;c.append("type",t),t==="text"?c.append("url",e.text):c.append("url",e.url);const n=await fetch("http://localhost:3000/api/posts/create",{method:"POST",credentials:"include",body:c});let i;try{i=await n.json()}catch{}if(n.ok&&(i!=null&&i.success))chrome.notifications.create({type:"basic",iconUrl:"images/icon-128.png",title:"Saved Successfully",message:"Content added to Archivist AI."});else throw n.status===401?new Error("Unauthenticated"):new Error("Save Failed")}catch(e){chrome.notifications.create({type:"basic",iconUrl:"images/icon-128.png",title:e.message==="Unauthenticated"?"Authentication Required":"Error",message:e.message==="Unauthenticated"?"Please login using the Archivist AI popup first.":"Could not save. Please check your connection."})}});
